<?php if (!defined('ABSPATH')) exit; get_header(); ?>
<div class="flavor-container py-8"><h1 class="text-4xl font-bold mb-4">Biblioteca Comunitaria</h1><p class="text-lg text-gray-600 mb-8">Catálogo de libros disponibles para préstamo</p><div class="flex flex-col lg:flex-row gap-8"><aside class="lg:w-1/4"><?php include dirname(__FILE__) . '/filters.php'; ?></aside><main class="lg:w-3/4"><form method="get" class="mb-6 flex gap-2"><input type="text" name="s" placeholder="Buscar libros..." class="flex-1 px-4 py-3 border rounded-lg"/><button type="submit" class="px-6 py-3 bg-primary text-white rounded-lg">Buscar</button></form><?php $q = new WP_Query(array('post_type' => 'biblioteca', 'posts_per_page' => 12)); if ($q->have_posts()) : echo '<div class="grid md:grid-cols-2 xl:grid-cols-4 gap-6">'; while ($q->have_posts()) : $q->the_post(); $autor = get_post_meta(get_the_ID(), '_autor', true); $isbn = get_post_meta(get_the_ID(), '_isbn', true); $disponible = get_post_meta(get_the_ID(), '_disponible', true); echo '<article class="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-xl transition-all">'; if (has_post_thumbnail()) the_post_thumbnail('medium', array('class' => 'w-full aspect-[2/3] object-cover')); echo '<div class="p-4"><h2 class="text-lg font-bold mb-2 line-clamp-2"><a href="' . get_permalink() . '">' . get_the_title() . '</a></h2>'; if ($autor) echo '<p class="text-sm text-gray-600 mb-3">' . esc_html($autor) . '</p>'; echo '<div class="mb-3">' . ($disponible ? '<span class="text-xs bg-green-100 text-green-700 px-3 py-1 rounded-full">Disponible</span>' : '<span class="text-xs bg-red-100 text-red-700 px-3 py-1 rounded-full">Prestado</span>') . '</div>'; echo '<a href="' . get_permalink() . '" class="block text-center px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark text-sm">Ver Detalles</a></div></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><h3 class="text-2xl font-bold">No hay libros</h3></div>'; endif; wp_reset_postdata(); ?></main></div></div><?php get_footer(); ?>
